+
+        totals.lanes_run += 1;
+        if lane_passed {
+            totals.lanes_passed += 1;
+        }
+        totals.oracles_pass += pass_count;
+        totals.oracles_fail += fail_count;
+        totals.oracles_skip += skip_count;
+
